module down_counter_5bit(
    input clk,
    input rst,
    output [4:0] count
);

    reg [4:0] decrement_reg;

    always @(posedge clk) begin
        if (!rst) begin
            decrement_reg <= 5'b11111;
        end else begin
            decrement_reg <= decrement_reg - 1;
        end
    end

    assign count = decrement_reg;

endmodule
